import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How much should I tip at a restaurant?", a: "The standard tip at a restaurant in the US is 15-20% of the pre-tax bill. 15% is considered standard, 18-20% is good, and 20-25% is generous for exceptional service." },
  { q: "Do I tip on the pre-tax or post-tax amount?", a: "You can tip on either, but tipping on the pre-tax amount is technically correct. The difference is small - tipping 20% on a $100 bill vs. a $108 bill (with 8% tax) is only $1.60." },
  { q: "How do I split a bill evenly?", a: "Divide the total bill (including tip) by the number of people. For example, a $120 total bill for 4 people means each person pays $30. This calculator handles the split automatically." },
  { q: "Should I tip on delivery orders?", a: "Yes. Tipping on delivery is standard - 15-20% of the order total, or a minimum of $3-$5. Tip generously in bad weather or for long-distance deliveries." },
  { q: "What is the standard tip for different services?", a: "Restaurant servers: 15-20%. Bartenders: $1-2/drink or 15-20%. Hotel housekeeping: $3-5/night. Food delivery: 15-20% or $3-5 minimum. Taxi/rideshare: 15-20%. Hair stylists: 15-20%. Valet: $2-5 when picking up." },
  { q: "Is it ever okay not to tip?", a: "In the US, tipping is expected for table service, delivery, and personal services. However, it is generally not expected for counter service at fast food, coffee shops (though appreciated), and retail stores. In countries with service-included pricing, tipping is not expected." },
  { q: "How do I tip when the service was poor?", a: "Even for poor service, tipping 10-15% is courteous in the US. If service was genuinely problematic, speaking with a manager is more effective than leaving no tip. The issue may have been outside the server's control (kitchen delays, etc.)." },
];

export default function TipCalculator() {
  useCurrencyVersion();
  const [bill, setBill] = useState(60);
  const [tipPct, setTipPct] = useState(18);
  const [people, setPeople] = useState(2);

  const tip = bill * (tipPct / 100);
  const total = bill + tip;
  const perPerson = total / people;
  const tipPerPerson = tip / people;

  const fmt = (n: number) => formatCurrencyValue(n, { minimumFractionDigits: 2 });

  return (
    <>
      <SEOHead
        title="Free Tip Calculator Online - Calculate Tip and Split Bill Instantly | CalcHive"
        description="Free online tip calculator. Calculate tip amount and split the total bill between any number of people instantly. 100% free for everyone, works on all devices, no signup required."
        canonical="/tip-calculator"
        keywords="free tip calculator, tip calculator online free, bill split calculator free, restaurant tip calculator free, how much to tip calculator free"
        category="Finance Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-lime-600 dark:text-lime-400 bg-lime-50 dark:bg-lime-950/50 px-3 py-1 rounded-full mb-4 inline-block">Everyday</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Tip Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free tip calculator to calculate the right tip and split the bill between any number of people. This tip calculator online free also works as a bill split calculator free, restaurant tip calculator free, and how much to tip calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="bill" label="Bill Amount" value={bill} min={1} max={1000} step={0.5} onChange={setBill} format={v => fmt(v)} testId="input-bill" />
            <div>
              <label className="text-sm font-semibold text-foreground mb-3 block">Tip Percentage - {tipPct}%</label>
              <div className="flex flex-wrap gap-2 mb-3">
                {[10, 15, 18, 20, 25].map(p => <button key={p} onClick={() => setTipPct(p)} className={`px-4 py-2 rounded-xl text-sm font-bold border transition-all ${tipPct === p ? "bg-lime-500 text-white border-lime-500" : "bg-card text-muted-foreground border-border hover:border-lime-400"}`}>{p}%</button>)}
              </div>
              <SliderInput id="tip" label="" value={tipPct} min={0} max={50} step={1} onChange={setTipPct} format={v => `${v}%`} testId="input-tip" />
            </div>
            <SliderInput id="people" label="Number of People" value={people} min={1} max={20} step={1} onChange={setPeople} format={v => `${v} ${v === 1 ? "person" : "people"}`} testId="input-people" />
          </div>
          <motion.div key={`${bill}-${tipPct}-${people}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-lime-500 to-lime-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Per Person Total</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-per-person">{fmt(perPerson)}</p>
              <p className="text-white/70 text-sm mt-1">{fmt(tipPerPerson)} tip per person</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[{ label: "Tip Amount", value: fmt(tip) }, { label: "Bill + Tip", value: fmt(total) }, { label: "Per Person", value: fmt(perPerson) }].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-base font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate the Right Tip Amount for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Calculating a tip is simple: multiply your bill by the tip percentage as a decimal, then add it to the bill for the total. To split, divide the total by the number of people.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Tip Amount = Bill  x  (Tip %  x  100)</p>
            <p>Total = Bill + Tip Amount</p>
            <p>Per Person = Total  x  Number of People</p>
            <p className="text-xs text-muted-foreground mt-2">Example: $80 bill, 20% tip, 4 people</p>
            <p>Tip = $80  x  0.20 = $16.00</p>
            <p>Total = $80 + $16 = $96.00</p>
            <p>Per Person = $96  x  4 = $24.00</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Split a Bill Between Any Number of People</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Service", "Standard Tip", "Exceptional Service", "Notes"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Restaurant (sit-down)", "15-18%", "20-25%", "Tip on pre-tax amount"],
                  ["Bar / Bartender", "15-20% or $1-2/drink", "20%+", "Round up on small tabs"],
                  ["Food Delivery", "15-20%", "25%+", "Minimum $3-$5 regardless"],
                  ["Taxi / Rideshare", "15-20%", "20-25%", "Add extra for help with luggage"],
                  ["Hotel Housekeeping", "$3-5/night", "$5-10/night", "Leave daily, not just at checkout"],
                  ["Hairstylist / Barber", "15-20%", "20-25%", "Tip on total service price"],
                  ["Spa / Massage", "15-20%", "20-25%", "Cash tips preferred"],
                  ["Valet Parking", "$2-5 at pickup", "$5-10", "At the time of pickup"],
                  ["Movers", "$20-50/mover", "$50-100/mover", "Based on job complexity"],
                ].map(([service, standard, exceptional, notes]) => (
                  <tr key={service} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{service}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{standard}</td>
                    <td className="py-2.5 px-4 text-lime-600 dark:text-lime-400 font-medium">{exceptional}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{notes}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Restaurant Tip and Bill Splitter for Everyone</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Bill Amount", "10% Tip", "15% Tip", "18% Tip", "20% Tip", "25% Tip"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  [20, 2, 3, 3.6, 4, 5],
                  [40, 4, 6, 7.2, 8, 10],
                  [60, 6, 9, 10.8, 12, 15],
                  [80, 8, 12, 14.4, 16, 20],
                  [100, 10, 15, 18, 20, 25],
                  [150, 15, 22.5, 27, 30, 37.5],
                  [200, 20, 30, 36, 40, 50],
                ].map(([bill, ...tips]) => (
                  <tr key={bill} className="hover:bg-muted/30">
                    <td className="py-2.5 px-3 font-semibold text-foreground">{fmt(bill)}</td>
                    {tips.map((t, i) => <td key={i} className="py-2.5 px-3 text-muted-foreground">{fmt(t)}</td>)}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/tip-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


